import{A as e,f as t,h as n,t as r}from"./chunks/plugin-vue_export-helper.I53torQa.js";var i=JSON.parse(`{"title":"SGLang 框架概览","description":"概述 SGLang 推理框架的前端 DSL 与后端运行时设计，及其 RadixAttention、约束解码、API 推测执行等核心优化技术。","frontmatter":{"title":"SGLang 框架概览","description":"概述 SGLang 推理框架的前端 DSL 与后端运行时设计，及其 RadixAttention、约束解码、API 推测执行等核心优化技术。"},"headers":[],"relativePath":"inference/sglang/introduction.md","filePath":"inference/sglang/introduction.md","lastUpdated":1782803909000}`),a={name:`inference/sglang/introduction.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="sglang-框架概览" tabindex="-1">SGLang 框架概览 <a class="header-anchor" href="#sglang-框架概览" aria-label="Permalink to “SGLang 框架概览”">​</a></h1><p>SGLang 是一个面向大语言模型（LLM）与视觉语言模型（VLM）的快速服务框架。它通过共同设计后端运行时与前端语言，使模型交互更快速、更可控。</p><h2 id="_1-核心能力" tabindex="-1">1. 核心能力 <a class="header-anchor" href="#_1-核心能力" aria-label="Permalink to “1. 核心能力”">​</a></h2><ul><li><strong>高效后端运行时</strong>：提供 RadixAttention 前缀缓存、压缩有限状态机约束解码、连续批处理、Token Attention（PagedAttention）、张量并行、FlashInfer 内核、分块预填充以及 INT4 / FP8 / AWQ / GPTQ 量化等优化。</li><li><strong>灵活前端语言</strong>：提供嵌入 Python 的 DSL，支持链式生成调用、高级提示、控制流、多模态输入、并行性与外部交互。</li></ul><h2 id="_2-从单轮对话到-lm-programs" tabindex="-1">2. 从单轮对话到 LM Programs <a class="header-anchor" href="#_2-从单轮对话到-lm-programs" aria-label="Permalink to “2. 从单轮对话到 LM Programs”">​</a></h2><p>传统上，LLM 服务主要面向简单的单轮对话：输入 Prompt，经过 Prefill + Decode 后输出结果。然而，随着大模型应用深入，LLM 越来越多地参与多轮规划、推理、工具调用与外部环境交互。这些场景通常不是简单单轮对话，而是：</p><ul><li>一个 Prompt 输出多个结果；</li><li>生成内容受 JSON 格式、关键词或正则表达式约束；</li><li>多个 LLM 调用之间穿插控制流。</li></ul><p>这种趋势标志着 LLM 使用方式从聊天向<strong>程序化使用</strong>转变，即通过类似编程语言的方式控制生成过程，称为 <strong>LM Programs</strong>。LM Programs 通常具有两个特征：</p><ol><li>包含多个 LLM 调用，并穿插控制流；</li><li>接收结构化输入并产生结构化输出，便于组合与集成。</li></ol><p>SGLang 正是为 LM Programs 设计的框架。</p><h2 id="_3-编译器式设计" tabindex="-1">3. 编译器式设计 <a class="header-anchor" href="#_3-编译器式设计" aria-label="Permalink to “3. 编译器式设计”">​</a></h2><p>当输入与输出之间是多对多关系时，存在大量延迟调度优化空间，这自然映射到编译器式的前后端设计。</p><h3 id="_3-1-前端-dsl" tabindex="-1">3.1 前端 DSL <a class="header-anchor" href="#_3-1-前端-dsl" aria-label="Permalink to “3.1 前端 DSL”">​</a></h3><p>前端是一种嵌入 Python 的 DSL。以下示例展示了一个使用“分支-解决-合并”提示方法评估论文与图像相关性的 LLM Program：</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">import</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> sglang </span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">as</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> sgl</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">@sgl.function</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">def</span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;"> multi_dimensional_judge</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">s</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">image_path</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">essay</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">):</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    s += sgl.image(image_path) + essay</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    s += </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;Is the essay related to the image?&quot;</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    s += sgl.select(sgl.S(</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;related&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">), </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">choices</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=[</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;Yes&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;No&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">])</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">    if</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> s[</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;related&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">] == </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;Yes&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">:</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">        forks = s.fork(</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">3</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span>
<span class="line"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">        for</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> i, f </span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">in</span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;"> enumerate</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(forks):</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">            f += </span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">f</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;Evaluate dimension </span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">{</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">i</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">}</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">: &quot;</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">            f += sgl.gen(</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">f</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;judgment_</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">{</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">i</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">}</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">        s.join(forks)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    s += </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;Summarize and score the paper ABCD.&quot;</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    s += sgl.gen(</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;summary&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">regex</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">r</span><span style="--shiki-light:#811F3F;--shiki-dark:#D16969;">&quot;</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;">\\{</span><span style="--shiki-light:#811F3F;--shiki-dark:#D16969;">.</span><span style="--shiki-light:#000000;--shiki-dark:#D7BA7D;">*</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;">\\}</span><span style="--shiki-light:#811F3F;--shiki-dark:#D16969;">&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>SGLang 后端执行时极大地简化了此类程序：相比使用 OpenAI 风格 API 编写等效程序，代码量可减少约 2.1 倍。</p><h2 id="_4-后端三大核心优化" tabindex="-1">4. 后端三大核心优化 <a class="header-anchor" href="#_4-后端三大核心优化" aria-label="Permalink to “4. 后端三大核心优化”">​</a></h2><h3 id="_4-1-radixattention-高效复用-kv-cache" tabindex="-1">4.1 RadixAttention：高效复用 KV Cache <a class="header-anchor" href="#_4-1-radixattention-高效复用-kv-cache" aria-label="Permalink to “4.1 RadixAttention：高效复用 KV Cache”">​</a></h3><p>在 LM Programs 中，多个生成调用常通过 <code>fork</code> 创建并行副本，且不同程序实例通常共享系统提示等公共前缀。SGLang V1 提出的 <strong>RadixAttention</strong> 在运行时自动、系统化地复用 KV Cache：</p><ul><li>将 Prompt 与生成结果的 KV Cache 保留在 Radix Tree 中；</li><li>支持高效的前缀搜索、复用、插入与驱逐；</li><li>结合 LRU 驱逐策略与缓存感知调度，提高命中率。</li></ul><p>RadixAttention 很快被 MoonCake、MemServe 等新型推理引擎采用，成为跨请求前缀共享的通用设计。</p><h3 id="_4-2-压缩有限状态机约束解码" tabindex="-1">4.2 压缩有限状态机约束解码 <a class="header-anchor" href="#_4-2-压缩有限状态机约束解码" aria-label="Permalink to “4.2 压缩有限状态机约束解码”">​</a></h3><p>LM Programs 常要求模型输出遵循特定格式（如 JSON Schema）。传统方法将正则表达式转换为有限状态机（FSM），逐 Token 检查并屏蔽无效 Token。当 FSM 中存在确定性的多 Token 转移路径时，逐 Token 处理效率低下。</p><p>SGLang 通过<strong>压缩 FSM</strong> 优化：将相邻的单一转换边压缩为单一边，从而识别可一次性解码的多个 Token，在一次前向传递中完成常量序列生成。</p><h3 id="_4-3-api-推测执行" tabindex="-1">4.3 API 推测执行 <a class="header-anchor" href="#_4-3-api-推测执行" aria-label="Permalink to “4.3 API 推测执行”">​</a></h3><p>对于 OpenAI 等黑盒 API，SGLang 通过<strong>推测执行（Speculative Execution）</strong> 降低多调用程序的延迟与成本。例如程序中连续调用 <code>gen(&quot;name&quot;)</code> 与 <code>gen(&quot;job&quot;)</code> 时，SGLang 可在第一次调用时忽略停止条件继续生成若干 Token，并在后续原语中匹配复用这些额外输出，从而节省一次 API 调用。</p><h2 id="_5-性能与生态" tabindex="-1">5. 性能与生态 <a class="header-anchor" href="#_5-性能与生态" aria-label="Permalink to “5. 性能与生态”">​</a></h2><p>SGLang V2 在不启用 RadixAttention 与约束解码的情况下，相比 vLLM 已展现出明显加速，部分场景甚至接近或超过 TRT-LLM。其性能优势主要源于更高效的工程实现、重叠调度（Overlap Scheduling）以及对 PD 分离、大规模 EP 等前沿技术的成功集成。</p><p>SGLang 的核心优势可概括为：</p><ul><li><strong>高性能实现</strong>：从 RadixAttention 到 Overlap Scheduling、PD 分离、专家并行，提供主流模型的 SOTA 部署支持。</li><li><strong>易于二次开发</strong>：代码结构清晰，社区活跃，便于定制与扩展。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>SGLang 不仅是一个推理引擎，更是一个面向 LLM Programs 的编程与执行框架。它通过前端 DSL 与后端运行时的协同设计，以及 RadixAttention、约束解码、API 推测执行等优化，为复杂大模型应用提供了高性能、可控制的解决方案。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ul><li><a href="https://github.com/sgl-project/sglang" target="_blank" rel="noreferrer">SGLang GitHub</a></li><li><a href="https://arxiv.org/abs/2501.13103" target="_blank" rel="noreferrer">SGLang 论文 v2</a></li></ul>`,34)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};